<script lang="ts">
  import { onMount } from 'svelte';
  import { api, type ReviewResult } from '../api';

  let results = $state<ReviewResult[]>([]);
  let scannedAt = $state('');
  let loading = $state(true);
  let fetchError = $state('');
  let selected = $state<ReviewResult | null>(null);

  const bucketOrder: Record<string, number> = { tradeable: 0, hot: 1, watch: 2 };
  const sorted = $derived(
    [...results].sort((a, b) => (bucketOrder[a.bucket] ?? 9) - (bucketOrder[b.bucket] ?? 9)),
  );

  async function load() {
    loading = true;
    try {
      const res = await api.review();
      results = res.results;
      scannedAt = res.scanned_at;
      fetchError = '';
    } catch (e) {
      fetchError = e instanceof Error ? e.message : 'Failed to load review';
    } finally {
      loading = false;
    }
  }

  onMount(() => {
    load();
  });

  function biasClass(bias: string): string {
    if (bias === 'long') return 'positive';
    if (bias === 'short') return 'negative';
    return 'faint';
  }

  function fmt(n: number, digits = 2): string {
    return n.toFixed(digits);
  }

  function fmtTime(iso: string): string {
    if (!iso) return '';
    return new Date(iso).toLocaleString();
  }
</script>

<div class="page">
  <div class="table-area">
    <div class="header-row">
      <h1 class="page-title">Watchlist Review</h1>
      <div class="header-right">
        {#if scannedAt}
          <span class="scanned-at">Scanned {fmtTime(scannedAt)}</span>
        {/if}
        <button class="btn-secondary" onclick={load} disabled={loading}>
          {loading ? 'Scanning…' : 'Refresh'}
        </button>
      </div>
    </div>

    {#if loading && results.length === 0}
      <div class="card empty">Scanning watchlist…</div>
    {:else if fetchError}
      <div class="card empty error">{fetchError}</div>
    {:else if sorted.length === 0}
      <div class="card empty">No instruments to review.</div>
    {:else}
      <div class="card no-pad">
        <table>
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Bucket</th>
              <th>Bias</th>
              <th class="right">D1 ADX</th>
              <th class="right">D1 CI</th>
              <th class="right">H4 Price/EMA20</th>
              <th>H4 Squeeze</th>
              <th>Value Zone</th>
              <th>H4 Aligned</th>
            </tr>
          </thead>
          <tbody>
            {#each sorted as r (r.instrument)}
              <tr
                class="row {selected?.instrument === r.instrument ? 'selected' : ''}"
                onclick={() => { selected = selected?.instrument === r.instrument ? null : r; }}
              >
                <td class="bold">{r.instrument}</td>
                <td><span class="badge bucket-{r.bucket}">{r.bucket}</span></td>
                <td class="bold small {biasClass(r.bias)}">{r.bias}</td>
                <td class="mono right">{fmt(r.d1.adx)}</td>
                <td class="mono right">{fmt(r.d1.ci)}</td>
                <td class="mono right">{fmt(r.h4.price_ema20_atr)}</td>
                <td>{r.h4.squeeze ? '✓' : '—'}</td>
                <td>{r.setup.in_value_zone ? '✓' : '—'}</td>
                <td>{r.setup.h4_aligned ? '✓' : '—'}</td>
              </tr>
              {#if selected?.instrument === r.instrument}
                <tr class="detail-row-tr">
                  <td colspan="9">
                    <div class="detail-panel">
                      <div class="detail-col">
                        <h3 class="section-title">W1</h3>
                        <div class="detail-row"><span class="label">Close</span><span class="mono">{fmt(r.w1.close, 5)}</span></div>
                        <div class="detail-row"><span class="label">EMA20</span><span class="mono">{fmt(r.w1.ema20, 5)}</span></div>
                        <div class="detail-row"><span class="label">ATR (pips)</span><span class="mono">{fmt(r.w1.atr_pips)}</span></div>
                        <div class="detail-row"><span class="label">Week used %</span><span class="mono">{fmt(r.w1.week_used_pct)}</span></div>
                      </div>
                      <div class="detail-col">
                        <h3 class="section-title">D1</h3>
                        <div class="detail-row"><span class="label">ADX / +DI / -DI</span><span class="mono">{fmt(r.d1.adx)} / {fmt(r.d1.plus_di)} / {fmt(r.d1.minus_di)}</span></div>
                        <div class="detail-row"><span class="label">CI</span><span class="mono">{fmt(r.d1.ci)}</span></div>
                        <div class="detail-row"><span class="label">EMA sep / ATR</span><span class="mono">{fmt(r.d1.ema_sep_atr)}</span></div>
                        <div class="detail-row"><span class="label">Price-EMA20 / ATR</span><span class="mono">{fmt(r.d1.price_ema20_atr)}</span></div>
                        <div class="detail-row"><span class="label">BB %B / width-ATR</span><span class="mono">{fmt(r.d1.bb_pct_b)} / {fmt(r.d1.bb_width_atr)}</span></div>
                        <div class="detail-row"><span class="label">Trend %</span><span class="mono">{fmt(r.d1.trend_pct)}</span></div>
                      </div>
                      <div class="detail-col">
                        <h3 class="section-title">H4</h3>
                        <div class="detail-row"><span class="label">ADX / CI</span><span class="mono">{fmt(r.h4.adx)} / {fmt(r.h4.ci)}</span></div>
                        <div class="detail-row"><span class="label">Price-EMA20 / ATR</span><span class="mono">{fmt(r.h4.price_ema20_atr)}</span></div>
                        <div class="detail-row"><span class="label">Squeeze</span><span class="mono">{r.h4.squeeze ? 'yes' : 'no'}</span></div>
                      </div>
                      {#if r.notes?.length}
                        <div class="detail-col notes-col">
                          <h3 class="section-title">Notes</h3>
                          <ul class="notes-list">
                            {#each r.notes as note}
                              <li>{note}</li>
                            {/each}
                          </ul>
                        </div>
                      {/if}
                    </div>
                  </td>
                </tr>
              {/if}
            {/each}
          </tbody>
        </table>
      </div>
    {/if}
  </div>
</div>

