<script lang="ts">
  import { navState, PAGE_TITLES, accountState, setActiveAccount, activeAccountLabel } from '../stores/nav.svelte';
  import { themeStore } from '../stores/theme.svelte';

  interface Props {
    onRefresh: () => void;
  }

  let { onRefresh }: Props = $props();

  let menuOpen = $state(false);
  let switcherEl: HTMLDivElement | undefined;

  function toggleMenu() {
    menuOpen = !menuOpen;
  }

  function chooseAccount(index: number) {
    setActiveAccount(index);
    menuOpen = false;
  }

  function handleWindowClick(e: MouseEvent) {
    if (menuOpen && switcherEl && !switcherEl.contains(e.target as Node)) {
      menuOpen = false;
    }
  }

  function handleKeydown(e: KeyboardEvent) {
    if (e.key === 'Escape') menuOpen = false;
  }
</script>

<svelte:window onclick={handleWindowClick} onkeydown={handleKeydown} />

<header class="topbar">
  <span class="page-title">{PAGE_TITLES[navState.currentPage]}</span>
  <div class="topbar-actions">
    <div class="account-switcher" bind:this={switcherEl}>
      <button
        class="account-switcher-btn"
        onclick={toggleMenu}
        aria-label="Switch account"
        aria-haspopup="listbox"
        aria-expanded={menuOpen}
      >
        <i class="ti ti-building-bank" aria-hidden="true"></i>
        <span>{activeAccountLabel()}</span>
        <i class="ti ti-chevron-down" aria-hidden="true"></i>
      </button>
      {#if menuOpen}
        <ul class="account-menu" role="listbox">
          {#if accountState.accounts.length === 0}
            <li class="account-menu-empty">No accounts available</li>
          {:else}
            {#each accountState.accounts as acc, i (acc.id)}
              <li>
                <button
                  class="account-menu-item {i === accountState.activeIndex ? 'active' : ''}"
                  role="option"
                  aria-selected={i === accountState.activeIndex}
                  onclick={() => chooseAccount(i)}
                >
                  <span>{acc.id}</span>
                  {#if acc.is_default}
                    <span class="default-tag">default</span>
                  {/if}
                  {#if i === accountState.activeIndex}
                    <i class="ti ti-check" aria-hidden="true"></i>
                  {/if}
                </button>
              </li>
            {/each}
          {/if}
        </ul>
      {/if}
    </div>
    <button class="icon-btn" onclick={onRefresh} aria-label="Refresh data">
      <i class="ti ti-refresh" aria-hidden="true"></i>
    </button>
    <button class="icon-btn" onclick={themeStore.toggle} aria-label="Toggle theme">
      <i class="ti {themeStore.current === 'dark' ? 'ti-sun' : 'ti-moon'}" aria-hidden="true"></i>
    </button>
    <button class="icon-btn" aria-label="Alerts">
      <i class="ti ti-bell" aria-hidden="true"></i>
    </button>
  </div>
</header>

